import heapq

def minPath(grid, k):
    n = len(grid)
    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    queue = []
    visited = set()

    for i in range(n):
        for j in range(n):
            heapq.heappush(queue, (grid[i][j], i, j, 1, [grid[i][j]]))

    while queue:
        val, x, y, steps, path = heapq.heappop(queue)
        if (x, y, steps) in visited:
            continue
        visited.add((x, y, steps))

        if steps == k:
            return path

        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < n and 0 <= ny < n:
                heapq.heappush(queue, (grid[nx][ny], nx, ny, steps + 1, path + [grid[nx][ny]]))

def tri(n):
    sequence = [0] * (n + 1)
    sequence[0] = 1
    sequence[1] = 3
    for i in range(2, n + 1):
        if i == 2:
            sequence[i] = 2
        elif i % 2 == 0:
            sequence[i] = 1 + i / 2
        else:
            sequence[i] = sequence[i - 1] + sequence[i - 2] + sequence[i + 1] if i < n else sequence[i - 1] + sequence[i - 2] + sequence[i - 3]
    # fix the sequence to make tri(n+1) calculable 
    if n > 2:
        for i in range(n, 2, -1):
            if i % 2 != 0:
                sequence[i-3] = sequence[i] - sequence[i-1] - sequence[i-2]
    return sequence[:n+1]

def is_nested(string):
    stack = []
    for char in string:
        if char == '[':
            stack.append(char)
        elif char == ']':
            if stack:
                stack.pop()
            else:
                return False
    return len(stack) > 0 and any(len(stack) > 1 for _ in range(len(string)))

